section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/survey-design.json",
  "title": "Survey Design",
  "type": "object",
  "required": [
    "artefact_id",
    "research_objective",
    "question_bank",
    "flow",
    "pilot_log",
    "analysis_plan",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "research_objective": {
      "type": "string",
      "description": "single, falsifiable objective",
      "minLength": 1
    },
    "question_bank": {
      "type": "array",
      "description": "{type, text, scale, rationale}",
      "minItems": 1
    },
    "flow": {
      "type": "array",
      "description": "screener -> easy -> core -> demographics -> open-end",
      "minItems": 1
    },
    "pilot_log": {
      "type": "object",
      "description": "5-10 person pilot results"
    },
    "analysis_plan": {
      "type": "object",
      "description": "pre-registered statistical tests"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
  "artefact_id": "survey-design-2026-05-23",
  "research_objective": "draft",
  "question_bank": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "flow": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "pilot_log": {
    "key": "value"
  },
  "analysis_plan": {
    "key": "value"
  },
  "evidence": [
    {
      "source": "https://example.com/transcript/1",
      "citation": "verbatim user quote"
    }
  ]
}
